var chart_component_default = `<!-- =========================\r
TRADING VIEW CONTAINER\r
isFullscreen === FULLSCREEN\r
========================== -->\r
<div class="trading-view-container" [class.fullscreen]="isFullscreen">\r
\r
  <!-- =========================\r
  CHART AREA\r
  ========================== -->\r
  <div class="chart-area">\r
\r
    <!-- ===== MAIN CHART ===== -->\r
    <div class="chart-container" (dblclick)="toggleFullscreen()" (touchstart)="onTouchStart($event)"\r
      (touchmove)="onTouchMove($event)" (touchend)="onTouchEnd($event)" (mousedown)="onMouseDown($event)"\r
      (mousemove)="onMouseMove($event)" (mouseup)="onMouseUp($event)" (mouseleave)="onMouseUp($event)"\r
      (wheel)="onWheel($event)" [class.interacting]="isInteracting" [attr.data-gesture]="gestureType">\r
      <!-- CHART -->\r
      <canvas baseChart [data]="chartData" [options]="chartOptions" [type]="'candlestick'" #chartCanvas></canvas>\r
\r
      <!-- ===== SYMBOL TITLE (OVERLAY \u2013 ALWAYS ALLOWED) ===== -->\r
      @if (selectedSymbolName) {\r
        <div class="chart-title">\r
          @if (selectedSymbol?.Icon) {\r
            <img class="chart-title__icon" [src]="getSymbolIcon()" alt="Symbol icon" />\r
          }\r
          <span class="chart-title__text">\r
            {{ selectedSymbolName }} {{ selectedTimeframe }}\r
          </span>\r
        </div>\r
      }\r
\r
      <!-- ===== CURRENT PRICE BADGE (OVERLAY \u2013 ALWAYS ALLOWED) ===== -->\r
      @if (currentPrice) {\r
        <div class="current-price-badge" [style.top.px]="getCurrentPricePixel()"\r
          [style.right.px]="10">\r
          {{ currentPrice | number:'1.2-8' }}\r
        </div>\r
      }\r
\r
      <!-- ===== INTERACTION FEEDBACK ===== -->\r
      @if (isInteracting && gestureType) {\r
        <div class="interaction-overlay" [attr.data-gesture]="gestureType"></div>\r
      }\r
\r
      <!-- ===== AXIS ZONES ===== -->\r
      @if (!isInteracting) {\r
        <div class="axis-zones">\r
          <div class="x-axis-zone"></div>\r
          <div class="y-axis-zone"></div>\r
        </div>\r
      }\r
\r
      <!-- Exit fullscreen button removed per request; exit still available via double-click and existing logic. -->\r
    </div>\r
\r
    <!-- =========================\r
    MINI TOOLBAR (NORMAL MODE ONLY)\r
    ========================== -->\r
    @if (!isFullscreen) {\r
      <div class="chart-mini-toolbar">\r
        <div class="toolbar-group">\r
          <label class="toolbar-field exchange-field">\r
            <select [(ngModel)]="selectedExchange" (change)="onExchangeChange(selectedExchange)" class="toolbar-select">\r
              @for (ex of exchanges; track ex) {\r
                <option [ngValue]="ex">\r
                  {{ ex.Name }}\r
                </option>\r
              }\r
            </select>\r
          </label>\r
          <label class="toolbar-field symbol-field">\r
            <select [(ngModel)]="selectedSymbol" (change)="onSymbolChange(selectedSymbol)" class="toolbar-select">\r
              @for (symbol of availableSymbols; track symbol) {\r
                <option [ngValue]="symbol">\r
                  {{ symbol.SymbolName }}\r
                </option>\r
              }\r
            </select>\r
          </label>\r
          <label class="toolbar-field timeframe-field">\r
            <select [(ngModel)]="selectedTimeframe" (change)="onTimeframeChange(selectedTimeframe)"\r
              class="toolbar-select">\r
              @for (tf of visibleTimeframes; track tf) {\r
                <option [value]="tf.value">\r
                  {{ tf.label }}\r
                </option>\r
              }\r
            </select>\r
          </label>\r
        </div>\r
        <div class="toolbar-actions">\r
          <button type="button" class="toolbar-btn settings-btn" (click)="toggleSettings()" aria-label="Instellingen">\r
            \u2699\r
          </button>\r
        </div>\r
      </div>\r
    }\r
  </div>\r
\r
  <!-- =========================\r
  SETTINGS PANEL (NORMAL MODE ONLY)\r
  ========================== -->\r
  @if (showSettings && !isFullscreen) {\r
    <div class="settings-panel-overlay">\r
      <button class="settings-close-btn" (click)="toggleSettings()">\u2715</button>\r
\r
      <label>\r
        <input type="checkbox" [(ngModel)]="showBoxes" (change)="onBoxesToggle()" />\r
        Show Boxes\r
      </label>\r
\r
      <label>\r
        <input type="checkbox" [(ngModel)]="showKeyZones" (change)="onToggleKeyZones()" />\r
        Key Zones\r
      </label>\r
\r
      @if (showKeyZones) {\r
        <div>\r
          <label>\r
            <input type="checkbox" [checked]="allTimeframesEnabled" (change)="onAllTimeframesToggle($event)" />\r
            All Timeframes\r
          </label>\r
          @for (tf of availableTimeframes; track tf) {\r
            <label>\r
              <input type="checkbox" [checked]="timeframeEnabled(tf)" (change)="onTimeframeToggle(tf, $event)" />\r
              {{ tf | uppercase }}\r
            </label>\r
          }\r
        </div>\r
      }\r
\r
      <label>\r
        <input type="checkbox" [(ngModel)]="showOrders" (change)="onOrdersToggle()" />\r
        Trade Orders\r
      </label>\r
\r
      <label>\r
        <input type="checkbox" [(ngModel)]="showIndicators" (change)="onToggleIndicators()" />\r
        Capital Flow Signals\r
      </label>\r
\r
      <!-- Capital Flow Signal Tiers -->\r
      @if (showIndicators) {\r
        <div class="capital-flow-tier-section">\r
          <div class="section-title">Capital Flow Signals \u2013 Tiers</div>\r
          <label>\r
            <input type="checkbox" [checked]="capitalFlowFilter.bronze" (change)="onTierToggle('bronze', $event)" />\r
            Bronze\r
          </label>\r
          <label>\r
            <input type="checkbox" [checked]="capitalFlowFilter.silver" (change)="onTierToggle('silver', $event)" />\r
            Silver\r
          </label>\r
          <label>\r
            <input type="checkbox" [checked]="capitalFlowFilter.gold" (change)="onTierToggle('gold', $event)" />\r
            Gold\r
          </label>\r
          <label>\r
            <input type="checkbox" [checked]="capitalFlowFilter.platinum" (change)="onTierToggle('platinum', $event)" />\r
            Platinum\r
          </label>\r
        </div>\r
      }\r
\r
      <label>\r
        <input type="radio" name="boxMode" value="boxes" [(ngModel)]="boxMode" (click)="onBoxModeChange('boxes')" />\r
        Trade Boxes\r
      </label>\r
\r
      <label>\r
        <input type="radio" name="boxMode" value="all" [(ngModel)]="boxMode" (click)="onBoxModeChange('all')" />\r
        Alle Boxes\r
      </label>\r
    </div>\r
  }\r
</div>\r
\r
<!-- =========================\r
FOOTER (NORMAL MODE ONLY)\r
========================== -->\r
<div class="app-footer" [class.hidden]="isFullscreen">\r
  <button class="footer-btn compact-toggle" (click)="toggleFullscreen()">\r
    \u{1F5D6} Fullscreen\r
  </button>\r
\r
  <button class="footer-btn" (click)="navigate('chart')">\u{1F4CA} Grafiek</button>\r
  <button class="footer-btn" (click)="navigate('orders')">\u{1F4BC} Orders</button>\r
  <button class="footer-btn" (click)="navigate('watchlist')">\u{1F441}\uFE0F Watchlist</button>\r
  <button class="footer-btn" (click)="navigate('balance')">\u{1F4B0} Balance</button>\r
  <button class="footer-btn" (click)="navigate('dashboard')">\u2699\uFE0F Settings</button>\r
</div>`;

