var account_balance_component_default = `<div class="balance-root">\r
  <!-- Header -->\r
  <div class="balance-content">\r
    @if (!loading) {\r
      <div class="wl-header">\r
        <button type="button" class="wl-btn" (click)="back()">\r
          <span class="icon">\u21A9</span>\r
        </button>\r
        <button type="button" class="wl-btn" (click)="refresh()">\r
          <span class="icon">\u27F3</span>\r
        </button>\r
        <div class="spacer"></div>\r
        <h2>Account Balance</h2>\r
      </div>\r
    }\r
\r
    @if (loading) {\r
      <div class="loader"></div>\r
    }\r
    @if (error) {\r
      <div class="error">{{ error }}</div>\r
    }\r
\r
    <div class="component-wrapper" style="position: relative;">\r
      @if (loading) {\r
        <div class="mtb-overlay">\r
          <span class="mtb-spinner large"></span>\r
        </div>\r
      }\r
      @if (!loading && balanceData) {\r
        <!-- Main Balance Cards -->\r
        <div class="bal-cards">\r
          @for (item of uiBalanceCards; track trackIndex($index, item)) {\r
            <div class="bal-card group">\r
              <div class="aura"></div>\r
              <div class="shimmer bal-shimmer"></div>\r
              <div class="bal-head">\r
                <div class="icon-box">\r
                  <!-- Placeholder icon mapping -->\r
                  <span class="bal-icon" [ngClass]="'icon-' + item.icon">\r
                    {{ item.icon === 'wallet' ? '\u{1F4BC}' : (item.icon === 'dollar' ? '\u{1F4B2}' : '\u{1F4CA}') }}\r
                  </span>\r
                </div>\r
                <div class="bal-info">\r
                  <div class="bal-label">{{ item.label }}</div>\r
                  <div class="bal-value">{{ item.value }}</div>\r
                </div>\r
                @if (item.change) {\r
                  <div class="bal-change" [ngClass]="item.positive ? 'pos' : 'neg'">\r
                    <span>{{ item.change }}</span>\r
                  </div>\r
                }\r
              </div>\r
            </div>\r
          }\r
        </div>\r
        <!-- P/L Cards -->\r
        <div class="bal-pl-grid">\r
          @for (p of uiPnlCards; track trackIndex($index, p)) {\r
            <div class="bal-pl-card group" [ngClass]="p.positive ? 'pos' : 'neg'">\r
              <div class="shimmer bal-shimmer"></div>\r
              <div class="bal-pl-label">{{ p.label }}</div>\r
              <div class="bal-pl-value" [ngClass]="p.positive ? 'pos' : 'neg'">{{ p.value }}</div>\r
              @if (p.change) {\r
                <div class="bal-pl-change" [ngClass]="p.positive ? 'pos' : 'neg'">\r
                  <span>{{ p.change }}</span>\r
                </div>\r
              }\r
            </div>\r
          }\r
        </div>\r
        <!-- Recent Transactions -->\r
        @if (uiRecentTransactions.length) {\r
          <div class="bal-trans">\r
            <h2 class="section-title">Recent Transactions</h2>\r
            <div class="bal-trans-list">\r
              @for (tx of uiRecentTransactions; track trackIndex($index, tx)) {\r
                <div class="bal-trans-card group">\r
                  <div class="shine"></div>\r
                  <div class="shimmer bal-shimmer"></div>\r
                  <div class="bal-trans-main">\r
                    <div class="bal-trans-left">\r
                      <div class="bal-trans-icon" [ngClass]="tx.type">\r
                        <span class="bal-icon" [ngClass]="tx.type">{{ tx.type === 'buy' ? '\u2193' : '\u2191' }}</span>\r
                      </div>\r
                      <div>\r
                        <div class="bal-trans-tags">\r
                          <span class="bal-tag" [ngClass]="tx.type">{{ tx.type.toUpperCase() }}</span>\r
                          <span class="bal-pair">{{ tx.pair }}</span>\r
                        </div>\r
                        <div class="bal-amount">{{ tx.amount }}</div>\r
                      </div>\r
                    </div>\r
                    <div class="bal-trans-right">\r
                      <div class="bal-value">{{ tx.value }}</div>\r
                      <div class="bal-time">{{ tx.time }}</div>\r
                    </div>\r
                  </div>\r
                </div>\r
              }\r
            </div>\r
          </div>\r
        }\r
        <!-- Balance Log Bottom Section -->\r
        @if (logEntries?.length) {\r
          <div class="balance-log-section">\r
            <div class="log-card gradient-frame">\r
              <div class="card-shimmer"></div>\r
              <div class="log-header-row">\r
                <h3>Balance Log</h3>\r
                <span class="log-count">{{ logEntries.length }} entries</span>\r
              </div>\r
              <div class="log-table-wrapper">\r
                <table class="log-table">\r
                  <thead>\r
                    <tr>\r
                      <th>Time</th>\r
                      <th>Type</th>\r
                      <th>Change</th>\r
                      <th>New Balance</th>\r
                      <th>Trade</th>\r
                    </tr>\r
                  </thead>\r
                  <tbody>\r
                    @for (l of logEntries; track trackIndex($index, l)) {\r
                      <tr class="log-row">\r
                        <td class="time">{{ l.CreatedAt | date:'HH:mm:ss' }}</td>\r
                        <td class="type">{{ l.ChangeType }}</td>\r
                        <td class="change" [ngClass]="pnlClass(l.ChangeAmount)">{{ l.ChangeAmount | number:'1.2-2' }}</td>\r
                        <td class="new-balance">{{ l.NewBalance | number:'1.2-2' }}</td>\r
                        <td class="trade">{{ l.TradeId }}</td>\r
                      </tr>\r
                    }\r
                  </tbody>\r
                </table>\r
              </div>\r
            </div>\r
          </div>\r
        }\r
      }\r
    </div>\r
  </div>\r
  <app-footer></app-footer>\r
</div>\r
\r
<app-footer></app-footer>\r
`;

